'use strict';
class UsabilityTestButton{
static#instance=null;
static#FORM_URL='https://docs.google.com/forms/d/e/1FAIpQLSdbGG_U5QoirsmRdmI4fApE94utku2rCkXQlftgr49tr6BCVg/viewform?usp=dialog';
#btn;
#formWindow=null;#abortController=new AbortController();
constructor(btn){
this.#btn=btn;
this.#btn.addEventListener('click',this.#handleClick,{signal:this.#abortController.signal});
document.body.appendChild(this.#btn);}
static init(){
if(UsabilityTestButton.#instance)return UsabilityTestButton.#instance;
localStorage.removeItem('nt_usability_test');
sessionStorage.removeItem('nt_usability_test');
if(!new URLSearchParams(window.location.search).has('test'))return null;
const btn=document.createElement('button');
btn.textContent='Open Test Form';
btn.className='usability-test-btn';
return(UsabilityTestButton.#instance=new UsabilityTestButton(btn));}
destroy(){
this.#abortController.abort();
this.#btn.remove();
UsabilityTestButton.#instance=null;}
#handleClick=(e)=>{
if(this.#formWindow&&!this.#formWindow.closed){
this.#formWindow.focus();
return;}
const width=520;
const height=window.screen.availHeight;
const left=window.screen.availWidth-width;
this.#formWindow=window.open(
UsabilityTestButton.#FORM_URL,'nt_test_form',
`width=${width},height=${height},left=${left},top=0,resizable=yes,scrollbars=yes`);};}
UsabilityTestButton.init();